{
  "steps": [
    {
      "text": "Open your web browser and navigate to `git-scm.com/downloads`. This is the official website for Git, and it will automatically detect your operating system.",
      "title": "Open the Git Website"
    },
    {
      "text": "Click the **Download** button matching your operating system (Windows, macOS, or Linux). Wait for the installation file to finish downloading to your computer.",
      "title": "Download the Installer"
    },
    {
      "text": "Locate the downloaded file in your computer's Downloads folder. Double-click the file to launch the Git setup wizard. If prompted by your system's security, click **Allow** or **Yes** to proceed.",
      "title": "Launch the Installer"
    },
    {
      "text": "Click **Next** through the installation screens to accept all the default configuration options. When you reach the final screen, click **Install** and wait for the progress bar to finish.",
      "title": "Accept Default Settings"
    },
    {
      "text": "Once installed, open your command line tool. On Windows, click the Start menu and open **Git Bash**. On macOS, open the **Terminal** app from Applications > Utilities.",
      "title": "Open Your Terminal"
    },
    {
      "text": "Type `git --version` in your terminal and press **Enter**. You should see a message displaying the installed Git version, such as `git version 2.40.0`. This confirms Git is installed correctly!",
      "title": "Verify the Installation"
    }
  ]
}

{
  "steps": [
    {
      "text": "Park on a flat, solid surface away from traffic. Engage your parking brake completely and turn on your hazard lights to ensure your vehicle won't roll while you work.",
      "title": "Secure the Vehicle"
    },
    {
      "text": "Open your trunk and locate the spare tire, car jack, and lug wrench. Place them on the ground right next to the flat tire so they are within easy reach.",
      "title": "Gather Your Tools"
    },
    {
      "text": "Use the lug wrench to turn each lug nut counterclockwise about one-half turn. Do not remove them completely yet. You just need to break their resistance while the tire's weight is still on the ground.",
      "title": "Loosen the Lug Nuts"
    },
    {
      "text": "Place the jack under your vehicle's designated jacking point near the flat tire. Look for a reinforced metal rib beneath the doors. Check your owner's manual if you cannot find it.",
      "title": "Position the Jack"
    },
    {
      "text": "Turn the jack handle clockwise to raise the car. Keep lifting until the flat tire is about six inches off the ground. You need this extra space because the fully inflated spare will be taller than the flat.",
      "title": "Lift the Vehicle"
    },
    {
      "text": "Use the lug wrench or your fingers to unscrew the loosened lug nuts the rest of the way. Place the removed nuts together inside your hubcap or in a pocket so they do not roll away.",
      "title": "Remove the Lug Nuts"
    },
    {
      "text": "Grip the edges of the flat tire securely with both hands and pull it straight toward you to slide it off the wheel hub. Set the flat tire flat on the ground so it doesn't roll away.",
      "title": "Pull the Tire Off"
    }
  ]
}

{
  "steps": [
    {
      "text": "Bring your water to a boil, then let it sit for about one minute off the heat. You want the temperature around 200°F (93°C) so it does not burn the coffee.",
      "title": "Heat the Water"
    },
    {
      "text": "Place your empty French press on a flat surface and remove the lid. Add **coarse** coffee grounds to the bottom. A good starting ratio is 1 rounded tablespoon of coffee for every 4 ounces of water.",
      "title": "Add Coffee Grounds"
    },
    {
      "text": "Pour just enough hot water over the grounds to fully saturate them. You should see the coffee bubble and expand slightly. This releases trapped gases so the water can extract the flavor.",
      "title": "Pour Water to Bloom"
    },
    {
      "text": "Wait 30 seconds, then use a wooden or plastic spoon to gently stir the wet coffee grounds. This breaks the thick crust at the top and ensures all the grounds are evenly mixed.",
      "title": "Stir the Grounds"
    },
    {
      "text": "Pour the rest of your hot water into the carafe, filling it to your desired amount. Leave at least an inch of space at the top so the coffee does not overflow when you plunge later.",
      "title": "Fill the French Press"
    },
    {
      "text": "Place the lid onto the French press with the plunger pulled all the way up. **Do not push down yet.** Set a timer for 4 minutes and let the coffee steep undisturbed.",
      "title": "Place Lid and Steep"
    },
    {
      "text": "When the 4 minutes are up, firmly grasp the handle. Using the weight of your hand, slowly and steadily press the plunger straight down to the bottom. If you feel heavy resistance, pull up slightly and resume.",
      "title": "Plunge the Coffee"
    },
    {
      "text": "Pour the brewed coffee into your mug right away. Do not leave leftover coffee sitting in the French press with the grounds, as it will continue to brew and quickly become bitter.",
      "title": "Pour Immediately"
    }
  ]
}

{
  "steps": [
    {
      "text": "Remove all existing weeds, roots, and rocks from your planting area. Pull weeds from the base to ensure you get the entire root system. You should have a completely bare patch of dirt when finished.",
      "title": "Clear Weeds and Debris"
    },
    {
      "text": "Grab a handful of soil and squeeze it. It should hold its shape loosely but crumble easily when poked. If it forms a muddy ball, wait a few days for it to dry out before proceeding. If it's dusty, water it lightly and wait overnight.",
      "title": "Test Soil Moisture"
    },
    {
      "text": "Push a garden fork or spade into the soil to a depth of 10 to 12 inches. Lever the tool back to lift and break apart the compacted dirt. Tomatoes have deep roots, so repeat this across the entire bed until the soil is loose and airy.",
      "title": "Loosen the Soil Deeply"
    },
    {
      "text": "Pour aged compost or well-rotted manure over your loosened soil. Use a rake to spread it evenly until you have a layer about 2 to 3 inches thick across the entire planting area. This provides essential nutrients and retains moisture.",
      "title": "Spread Organic Compost"
    },
    {
      "text": "Sprinkle a continuous-release, calcium-rich tomato fertilizer over the compost layer. Follow the exact dosage instructions on the fertilizer package. Calcium is critical for tomatoes to prevent blossom end rot later in the season.",
      "title": "Add Tomato Fertilizer"
    },
    {
      "text": "Use a garden fork or hoe to blend the compost and fertilizer down into the top 6 to 8 inches of your native soil. Once mixed, drag a bow rake back and forth across the surface until the bed is flat, even, and free of large dirt clods.",
      "title": "Mix and Level the Bed"
    },
    {
      "text": "Spray the entire bed lightly with a garden hose using a gentle shower setting. Stop watering when the top two inches are damp. This settles the soil and activates the fertilizer, making the bed ready for your tomato transplants.",
      "title": "Water the Prepared Soil"
    }
  ]
}

{
  "steps": [
    {
      "text": "Clear a large, flat table. Lay your fabric out completely flat with the right side (the printed or front side) facing down. Smooth out any wrinkles with your hands so the fabric lies perfectly flat.",
      "title": "Prepare Your Workspace"
    },
    {
      "text": "Place your paper pillowcase pattern onto the fabric. Use a measuring tape to ensure the long edge of the pattern is an equal distance from the fabric's selvage (the finished factory edge) from top to bottom.",
      "title": "Align the Pattern"
    },
    {
      "text": "Insert a sewing pin at each of the four corners of your paper pattern. Push the pin down through the paper and fabric, then angle it back up through both layers to secure it. This anchors the pattern in place.",
      "title": "Pin the Corners"
    },
    {
      "text": "Place additional pins every 4 to 5 inches along all edges of the pattern. Keep the pins pointing inward and make sure the paper remains completely flat against the fabric without buckling or shifting.",
      "title": "Pin the Edges"
    },
    {
      "text": "Hold the fabric gently with your non-dominant hand to keep it steady. Using sharp fabric shears, start cutting exactly along the outer edge of the paper pattern using long, smooth strokes.",
      "title": "Begin Cutting"
    },
    {
      "text": "As you cut, keep the bottom blade of your scissors resting against the table. Do not lift the fabric into the air. This prevents shifting and ensures your cut edges remain straight and perfectly sized.",
      "title": "Keep the Shears Grounded"
    },
    {
      "text": "Carefully pull out all the pins and set the paper pattern aside. You should now see a perfectly rectangular fabric piece with clean, straight edges, ready to be folded and sewn into your pillowcase.",
      "title": "Unpin the Fabric"
    }
  ]
}

{
  "steps": [
    {
      "text": "Clip a digital tuner to your guitar's headstock and turn it on, or open a guitar tuning app on your smartphone. Make sure you are in a quiet room so the microphone only picks up your guitar.",
      "title": "Turn On Your Tuner"
    },
    {
      "text": "Pluck the thickest string open, without pressing down on any frets. Let it ring out clearly. This is your 6th string, and your target note for standard tuning is **E**.",
      "title": "Pluck the Thickest String (Low E)"
    },
    {
      "text": "Look at your tuner display while the string rings. It will show the letter of the closest note. If it says **D** or **D#**, your pitch is too low (flat). If it says **F**, your pitch is too high (sharp).",
      "title": "Read the Tuner Display"
    },
    {
      "text": "Follow the thickest string up to its specific tuning peg. Turn the peg slightly to tighten the string if the pitch is too low, or loosen the string if the pitch is too high. Listen as the pitch changes.",
      "title": "Adjust the Tuning Peg"
    },
    {
      "text": "Pluck the thickest string again. Keep making small adjustments to the peg until the tuner reads **E** and the needle hits the exact middle. The tuner screen usually turns green when perfectly in tune.",
      "title": "Center the Tuner Needle"
    },
    {
      "text": "Pluck the 5th string (the second thickest) and check the tuner. Adjust its peg until the tuner displays **A** and the needle centers. Always pluck the string again after turning to get an accurate reading.",
      "title": "Tune the A String"
    },
    {
      "text": "Repeat this exact process for the remaining four strings in order: the 4th string (**D**), 3rd string (**G**), 2nd string (**B**), and the thinnest 1st string (High **E**).",
      "title": "Tune the Remaining Strings"
    },
    {
      "text": "Changes in neck tension can cause strings to slip slightly while tuning. Pluck all six strings one by one from thickest to thinnest to double-check their tuning. Make any tiny final adjustments needed.",
      "title": "Do a Final Verification Check"
    }
  ]
}

{
  "steps": [
    {
      "text": "Turn your camera's main mode dial to **M** (Manual). This gives you full control over aperture, shutter speed, and ISO, preventing the camera from making automatic adjustments.",
      "title": "Switch to Manual Mode"
    },
    {
      "text": "Look through your viewfinder or at the screen and frame your subject. Press the shutter button down exactly halfway to wake up the camera's internal light meter.",
      "title": "Frame and Activate the Meter"
    },
    {
      "text": "Find the numbered scale at the bottom of your screen or viewfinder, usually ranging from `-3` to `+3` with `0` in the middle. The blinking mark indicates your current exposure.",
      "title": "Locate the Exposure Indicator"
    },
    {
      "text": "Turn the aperture dial to choose your f-stop. Select a lower number (like `f/2.8`) for a blurred background, or a higher number (like `f/11`) to keep the whole scene in focus.",
      "title": "Set Your Aperture"
    },
    {
      "text": "Rotate your shutter speed dial. Choose a fast speed (like `1/500`) to freeze action, or a slower speed (like `1/60`) for still subjects. Watch the light meter mark move.",
      "title": "Adjust the Shutter Speed"
    },
    {
      "text": "Press the ISO button and turn the dial to change the camera's sensitivity. Adjust the ISO value until the mark on your exposure meter sits exactly at `0` in the center of the scale.",
      "title": "Balance with ISO"
    },
    {
      "text": "Press the shutter button halfway one last time to confirm the meter still reads `0`. Once confirmed, press the button down completely to capture your properly exposed photo.",
      "title": "Verify and Take the Shot"
    }
  ]
}

{
  "steps": [
    {
      "text": "Stand tall with your feet slightly wider than shoulder-width apart. Point your toes outward at a slight angle, about 15 to 30 degrees. You should feel perfectly balanced and stable on both feet.",
      "title": "Set Your Foot Stance"
    },
    {
      "text": "Pull your shoulders back and lift your chest. Look straight ahead at a fixed point on the wall. Tighten your core muscles as if you are preparing to take a punch to the stomach.",
      "title": "Brace Your Upper Body"
    },
    {
      "text": "Begin the squat by pushing your hips backward. Imagine you are reaching your glutes back to sit in an invisible chair that is slightly behind you. Do not bend your knees just yet.",
      "title": "Push Your Hips Back"
    },
    {
      "text": "Bend your knees to slowly lower your body toward the floor. Keep your body weight centered over your mid-foot and heels. Watch your knees to ensure they track outward in the same direction as your toes.",
      "title": "Bend Your Knees to Lower"
    },
    {
      "text": "Continue lowering until your thighs are parallel to the floor. You will know you have reached proper depth when your hip crease drops just below the top of your knees. Hold this bottom position for one second.",
      "title": "Pause at Parallel"
    },
    {
      "text": "Push firmly through your heels to start standing back up. Keep your chest lifted and your core tight. Ensure your knees do not cave inward as you rise.",
      "title": "Drive Through Your Heels"
    },
    {
      "text": "Return to your fully upright starting position. Squeeze your glute muscles firmly at the top to complete the repetition. You are now in the correct posture to begin your next rep.",
      "title": "Squeeze Your Glutes"
    }
  ]
}

{
  "steps": [
    {
      "text": "Em uma tigela pequena, misture 1 xícara de água morna, 1 colher de sopa de açúcar e 10g de fermento biológico seco. Mexa suavemente com uma colher até os ingredientes se dissolverem.",
      "title": "Misture o fermento e a água"
    },
    {
      "text": "Deixe a mistura descansar intacta por 5 a 10 minutos. Você saberá que o fermento está pronto e ativo quando uma camada de espuma grossa se formar na superfície.",
      "title": "Aguarde a ativação espumar"
    },
    {
      "text": "Em uma tigela grande, adicione 3 xícaras de farinha de trigo e 1 colher de chá de sal. Misture bem os dois ingredientes secos usando uma colher ou fouet.",
      "title": "Prepare os ingredientes secos"
    },
    {
      "text": "Faça um buraco no centro da farinha e despeje toda a mistura de fermento espumosa. Use uma espátula ou colher de pau para puxar a farinha das bordas para o centro, misturando tudo.",
      "title": "Junte os líquidos aos secos"
    },
    {
      "text": "Continue mexendo até que a farinha absorva a água e a mistura se transforme em uma bola de massa irregular e pesada. A massa deve começar a desgrudar das bordas da tigela.",
      "title": "Forme a massa inicial"
    },
    {
      "text": "Polvilhe um pouco de farinha sobre uma bancada limpa e seca. Despeje a massa da tigela sobre essa superfície enfarinhada para iniciar a sova.",
      "title": "Transfira para a bancada"
    },
    {
      "text": "Empurre a massa para frente com a base da mão, dobre-a ao meio de volta para você e vire um quarto de volta. Repita esse movimento repetidamente por cerca de 10 minutos.",
      "title": "Sove a massa"
    },
    {
      "text": "Pare de sovar quando a massa estiver lisa, elástica e não grudar mais nas mãos. Para confirmar o ponto, estique um pequeno pedaço: se ele formar uma membrana fina sem rasgar, está pronto.",
      "title": "Verifique o ponto da massa"
    }
  ]
}

{
  "steps": [
    {
      "text": "Ubica las llaves de paso debajo del lavabo. Gíralas a la derecha hasta que topen. Abre el grifo para liberar la presión y confirmar que ya no sale agua.",
      "title": "Cierra el paso de agua"
    },
    {
      "text": "Coloca un tapón o un trapo sobre el desagüe del lavabo. Esto evitará que los tornillos u otras piezas pequeñas se caigan accidentalmente por la tubería.",
      "title": "Tapa el desagüe"
    },
    {
      "text": "Quita la tapita decorativa de la manija haciendo palanca. Usa un destornillador para aflojar el tornillo interno y tira de la manija hacia arriba para sacarla por completo.",
      "title": "Retira la manija del grifo"
    },
    {
      "text": "Usa una llave ajustable para girar la tuerca principal hacia la izquierda. Una vez que esté suelta, termínala de desenroscar con tus dedos y retírala del grifo.",
      "title": "Afloja la tuerca de retención"
    },
    {
      "text": "Tira del cartucho directamente hacia arriba para sacarlo. Si está atascado, usa unos alicates para jalarlo suavemente. Deberías ver un anillo de goma en su base.",
      "title": "Extrae el cartucho interno"
    },
    {
      "text": "Retira el anillo de goma desgastado de la base del cartucho y coloca uno nuevo del mismo tamaño. Si el cartucho completo está dañado, usa un repuesto nuevo.",
      "title": "Reemplaza el empaque de goma"
    },
    {
      "text": "Inserta el cartucho de nuevo en la base del grifo, alineando sus pestañas. Coloca la tuerca de retención encima y apriétala firmemente con la llave ajustable.",
      "title": "Instala el cartucho y la tuerca"
    },
    {
      "text": "Pon la manija de vuelta sobre el cartucho. Inserta el tornillo, apriétalo con el destornillador y presiona la tapita decorativa en su lugar.",
      "title": "Vuelve a colocar la manija"
    },
    {
      "text": "Gira las llaves de paso hacia la izquierda para abrir el agua. Abre y cierra el grifo. Revisa la base y el cuello para confirmar que el goteo desapareció por completo.",
      "title": "Abre el agua y verifica"
    }
  ]
}

{
  "steps": [
    {
      "text": "Click on **File** in the top-left corner of the application window. A menu or a new screen will appear showing your file management options.",
      "title": "Open the File Menu"
    },
    {
      "text": "Click on **Save As** from the menu. Use this option the first time you save a document so you can choose exactly where the file goes and what to name it.",
      "title": "Select Save As"
    },
    {
      "text": "Select a folder on your computer or cloud drive where you want to keep the file. Click **Browse** if you don't see your preferred folder in the list.",
      "title": "Choose a Save Location"
    },
    {
      "text": "Click inside the **File name** box and type a clear, descriptive name for your document. Avoid using special characters like `/` or `*` in the name.",
      "title": "Type the File Name"
    },
    {
      "text": "Click the **Save** button in the bottom-right corner of the window. The dialog box will close, returning you directly to your document.",
      "title": "Click the Save Button"
    },
    {
      "text": "Look at the title bar at the very top of your application window. You should now see the new file name you just typed, confirming your work is securely saved.",
      "title": "Verify the Save"
    }
  ]
}

{
  "steps": [
    {
      "text": "Place your motherboard on top of its cardboard box. Do not place it on the anti-static bag, as the outside can sometimes be conductive. Ensure you have your components and a standard Phillips-head screwdriver ready.",
      "title": "Prep the Motherboard"
    },
    {
      "text": "Lift the metal retention arm beside the motherboard's CPU socket. Align the golden triangle on the corner of the CPU with the triangle on the socket. Gently drop it in without pushing, then lower the arm to lock it. The plastic protective cover will pop off.",
      "title": "Install the CPU"
    },
    {
      "text": "Push down the plastic clips at the ends of the RAM slots. Align the notch on the bottom of your RAM stick with the ridge in the slot. Push down firmly on both ends of the stick until you hear a click and the clips snap back up to lock it.",
      "title": "Install the RAM"
    },
    {
      "text": "Locate the M.2 slot on the motherboard and remove its tiny screw. Slide the M.2 storage drive into the slot at a 30-degree angle. Push the raised end down flat against the motherboard and secure it using the tiny screw you just removed.",
      "title": "Install the M.2 SSD"
    },
    {
      "text": "Place the cooler over the CPU, aligning its screws with the motherboard's mounting brackets. Tighten the screws in an alternating cross pattern. Finally, plug the cooler's fan cable into the motherboard header labeled `CPU_FAN`.",
      "title": "Mount the CPU Cooler"
    },
    {
      "text": "Lay your computer case flat. Snap the metal I/O shield into the back cutout if it isn't pre-installed. Lower the motherboard into the case, aligning its ports with the I/O shield and its holes with the case standoffs. Secure it with the provided screws.",
      "title": "Mount Motherboard into the Case"
    },
    {
      "text": "Slide the power supply (PSU) into the bottom rear of the case with its fan facing the case's ventilation holes. Secure it to the back of the case using the four thick screws provided with the PSU. Route the attached cables behind the motherboard tray.",
      "title": "Install the Power Supply"
    },
    {
      "text": "Take the wide 24-pin cable from the PSU and plug it firmly into the long slot on the right side of the motherboard. Next, plug the 8-pin CPU power cable into the socket at the top left of the motherboard. Ensure both latches click securely into place.",
      "title": "Connect Main Power Cables"
    },
    {
      "text": "Remove the top two metal PCIe covers from the back of the case. Push down the plastic latch on the motherboard's top long PCIe slot. Push the GPU firmly into the slot until the latch clicks up. Secure the GPU's metal bracket to the case with two screws.",
      "title": "Install the Graphics Card (GPU)"
    },
    {
      "text": "Plug the necessary PCIe power cables from the power supply into the top of your GPU. Finally, locate the thin front panel case cables (labeled Power SW, Reset SW, USB, Audio) and plug them into the matching pins along the bottom edge of your motherboard.",
      "title": "Connect GPU and Front Panel Cables"
    }
  ]
}
